import React from "react";
import "./SplashVisual.css";

function SplashVisual(props) {
  const { theme, id } = props;
  return (
    <div className="splash-visual" id={id}>
      <div className="splash-visual__blobs" aria-hidden="true">
        <div
          className="splash-visual__blob splash-visual__blob--a"
          style={{ background: theme.highlight }}
        />
        <div
          className="splash-visual__blob splash-visual__blob--b"
          style={{ background: theme.imageHighlight }}
        />
        <div
          className="splash-visual__blob splash-visual__blob--c"
          style={{ background: theme.body }}
        />
      </div>
      <div className="splash-visual__stage" aria-hidden="true">
        <div
          className="splash-visual__ring splash-visual__ring--outer"
          style={{ borderColor: theme.imageHighlight }}
        />
        <div
          className="splash-visual__ring splash-visual__ring--mid"
          style={{ borderColor: theme.highlight }}
        />
        <div
          className="splash-visual__ring splash-visual__ring--inner"
          style={{ borderColor: theme.body }}
        />
        <div
          className="splash-visual__dot"
          style={{
            background: theme.body,
            boxShadow: `0 0 24px 4px ${theme.highlight}`,
          }}
        />
      </div>
    </div>
  );
}

export default SplashVisual;
